以下是用backtrader写的一个简单的回测示范，展示如何检查每一笔成交和平仓情况：

```python
import backtrader as bt
import backtrader.feeds as btfeeds

class MyStrategy(bt.Strategy):

    def __init__(self):
        self.sma = bt.indicators.SimpleMovingAverage(period=15)

    def next(self):
        if self.position:
            if self.data.close[0] < self.sma[0]:
                self.sell()
                print(f"SELL {self.data.datetime.date(0)} - Close: {self.data.close[0]:.2f}")
        elif self.data.close[0] > self.sma[0]:
            self.buy()
            print(f"BUY {self.data.datetime.date(0)} - Close: {self.data.close[0]:.2f}")

    def notify_order(self, order):
        if order.status in [order.Submitted, order.Accepted]:
            return

        if order.status in [order.Completed]:
            if order.isbuy():
                print(f"BUY EXECUTED {order.executed.date} - Price: {order.executed.price:.2f}")
            elif order.issell():
                print(f"SELL EXECUTED {order.executed.date} - Price: {order.executed.price:.2f}")
        elif order.status in [order.Canceled, order.Margin, order.Rejected]:
            print(f"Order {order.Status[order.status]}")


if __name__ == "__main__":
    cerebro = bt.Cerebro()
    cerebro.addstrategy(MyStrategy)

    data = btfeeds.YahooFinanceCSVData(
        dataname="example.csv",
        fromdate=datetime.datetime(2010, 1, 1),
        todate=datetime.datetime(2015, 12, 31),
        reverse=False,
    )
    cerebro.adddata(data)
    cerebro.broker.setcash(100000.0)
    cerebro.addsizer(bt.sizers.FixedSize, stake=100)

    print(f"Initial Portfolio Value: {cerebro.broker.getvalue():.2f}")
    cerebro.run()
    print(f"Final Portfolio Value: {cerebro.broker.getvalue():.2f}")
```

这个代码使用`MyStrategy`策略，并利用Simple Moving Average (SMA) 指标作为一个简单的交易信号。在策略中的`next()`方法下，代码检查当前头寸，并基于最新数据点的收市价和细节价之间的关系执行买卖操作。

请注意，这个示范代码只是说明如何在回测中检查每一笔成交和平仓情况，而不是实际交易策略。实际应用时，您需要根据您自己的交易策略进行修改。

在您的示例中，您只是用`price`参数下了一个限价单。要使用止损单，您需要额外下一个单独的止损单。以下是一个简单示范，如何在开仓后设置一个止损单:

```python
import backtrader as bt

class MyStrategy(bt.Strategy):

    def __init__(self):
        self.stop_order = None

    def next(self):
        if not self.position:  # 检查是否有持仓
            # 下单开仓，以194的价格买入, 并保存返回的订单到 self.order 实例变量中
            self.order = self.buy(price=194, exectype=bt.Order.Limit)

        elif self.order is not None and self.order.status == bt.Order.Completed:
            # 当前已经有持仓且订单已完成, 且没有止损单
            if self.stop_order is None or self.stop_order.status in [bt.Order.Canceled, bt.Order.Margin, bt.Order.Rejected]:
                # 设置一个止损单，止损价格设定为192
                self.stop_order = self.sell(price=192, exectype=bt.Order.Stop)

    def notify_order(self, order):
        if order.status in [order.Submitted, order.Accepted]:
            return

        if order.status in [order.Completed]:
            if order.isbuy():
                print(f"BUY EXECUTED {order.executed.date} - Price: {order.executed.price:.2f}")
            elif order.issell() and order != self.stop_order:
                print(f"SELL EXECUTED {order.executed.date} - Price: {order.executed.price:.2f}")

        elif order.status in [order.Canceled, order.Margin, order.Rejected]:
            print(f"Order {order.Status[order.status]}")
```

这个策略示例在无持仓的情况下提交一个限价单买入。当买入订单完成后，会检查是否有活跃的止损单，如果没有，则会使用 `self.sell(price=192, exectype=bt.Order.Stop)` 提交一个止损单。注意这里定义了一个`self.stop_order`实例变量来保持追踪止损单。当止损单执行时，`notify_order` 方法会通知您。

在Backtrader中，您可以通过在开仓时同时提交一个包含限价单（开仓）和止损单（平仓）的组合订单来实现设置止损。

以下是一个示例：

```python
import backtrader as bt

class MyStrategy(bt.Strategy):
    def __init__(self):
        self.pending_order = None
        self.bracket_order = None

    def next(self):
        if not self.position and self.pending_order is None:
            buy_order = self.buy(price=194, exectype=bt.Order.Limit, transmit=False)
            stop_order = self.sell(price=192, exectype=bt.Order.Stop, parent=buy_order, transmit=True)

            self.pending_order = buy_order
            self.bracket_order = stop_order

        if self.pending_order is not None and self.pending_order.status == bt.Order.Completed:
            self.pending_order = None

    def notify_order(self, order):
        if order.status in [order.Submitted, order.Accepted]:
            return

        if order.status in [order.Completed]:
            if order.isbuy():
                print(f"BUY EXECUTED {order.executed.date} - Price: {order.executed.price:.2f}")
            elif order.issell():
                print(f"SELL EXECUTED {order.executed.date} - Price: {order.executed.price:.2f}")

        elif order.status in [order.Canceled, order.Margin, order.Rejected]:
            self.pending_order = None
            print(f"Order {order.Status[order.status]}")
```

在这个示例中，在创建组合订单时，我们创建了其中的两个子订单：`buy_order`（限价开仓）和`stop_order`（止损平仓）。

`transmit=False`参数用于告诉模拟经纪人在还没有关联的止损单时，不要立即提交限价单。我们通过`parent=buy_order`参数将止损单关联到限价单。随后，通过设置`transmit=True`，我们通知模拟经纪人这个组合订单已经准备好了，可以在满足条件时执行它们。

这样，在满足开仓条件的同时，止损单也会被激活，无需再次操作。若后续需要修改止损位，请参考`self.broker.modify_order`方法。

注意，在实际应用中，这种方式可能会受限于您真实经纪商的实际交易平台提供的功能。因此，尽管在回测中使用组合订单可以更好地模拟止损机制，但要确保在实际交易时经纪商支持相同的功能。

在Backtrader中，您可以使用`notify_order(self, order)`方法来输出成交订单的具体信息。`order`对象包含了所有关于订单的信息，包括执行的价格、数量、佣金等。

以下是一个示例，展示了如何在日志中输出成交订单的具体信息：

```python
import backtrader as bt

class MyStrategy(bt.Strategy):

    def notify_order(self, order):
        if order.status in [order.Submitted, order.Accepted]:
            return

        if order.status in [order.Completed]:
            order_details = f"{order.executed.date(0)} - Price: {order.executed.price:.2f} - Size: {order.executed.size} - Commission: {order.executed.comm:.2f}"
            if order.isbuy():
                print(f"BUY EXECUTED - {order_details}")
            elif order.issell():
                print(f"SELL EXECUTED - {order_details}")

        elif order.status in [order.Canceled, order.Margin, order.Rejected]:
            print(f"Order {order.Status[order.status]}")
```

这个示例中，我们重写了`notify_order()`方法，以便在每次订单的状态发生改变时输出具体信息。我们将订单执行的日期、价格、数量和佣金的详细信息格式化为一个字符串，并在买入/卖出事件发生时输出。这将帮助您在回测过程中跟踪订单的执行情况。

抱歉给您带来困扰。您可以先将`order.executed.dt`属性转换为`str`类型，然后再输出。

以下是一个示例，展示了如何在`notify_order`方法中输出成交订单的日期:

```python
import backtrader as bt

class MyStrategy(bt.Strategy):

    def notify_order(self, order):
        if order.status in [order.Submitted, order.Accepted]:
            return

        if order.status in [order.Completed]:
            exec_date = self.data.num2date(order.executed.dt)  # 转换为 datetime 类型
            order_details = f"{exec_date.strftime('%Y-%m-%d')} - Price: {order.executed.price:.2f} - Size: {order.executed.size} - Commission: {order.executed.comm:.2f}"
            if order.isbuy():
                print(f"BUY EXECUTED - {order_details}")
            elif order.issell():
                print(f"SELL EXECUTED - {order_details}")

        elif order.status in [order.Canceled, order.Margin, order.Rejected]:
            print(f"Order {order.Status[order.status]}")
```

这个示例中，我们首先使用`self.data.num2date()`将整数日期转换为`datetime`对象，然后使用`strftime`方法格式化输出日期。

在Backtrader框架中，您可以在策略的`notify_order()`方法中检测止损订单是否被触发。当订单状态改变时，将调用`notify_order()`方法。通过检查订单的状态以及其是否为卖出订单（`order.issell()`），可以判断是否执行了止损。

以下是一个示例，展示了如何在`notify_order()`方法中输出被止损订单的情况：

```python
import backtrader as bt

class MyStrategy(bt.Strategy):

    def __init__(self):
        self.stop_order = None

    def next(self):
        if not self.position:
            self.buy(price=194, exectype=bt.Order.Limit)

        elif self.position.size > 0 and self.stop_order is None or self.stop_order.status in [self.stop_order.Canceled, self.stop_order.Margin, self.stop_order.Rejected]:
            self.stop_order = self.sell(price=192, exectype=bt.Order.Stop)

    def notify_order(self, order):

        if order.status in [order.Submitted, order.Accepted]:
            return

        if order.status in [order.Completed]:
            if order.isbuy():
                print(f"BUY EXECUTED {order.executed.date(0)} - Price: {order.executed.price:.2f}")
            elif order.issell():
                print(f"SELL EXECUTED {order.executed.date(0)} - Price: {order.executed.price:.2f}")

        elif order.status in [order.Canceled, order.Margin, order.Rejected]:
            print(f"Order {order.Status[order.status]}")

            # 检查是否为止损订单
            if order == self.stop_order:
                print("Stop order was cancelled or rejected")
                self.stop_order = None

        if order == self.stop_order and order.status == bt.Order.Completed:
            print("Stop order was executed")
            self.stop_order = None
```

这个示例中的策略是在价格为194的时候发出限价买入订单，并设置价格为192的止损卖出订单。然后，在`notify_order()`方法中检查订单是否为止损订单，如果是，则输出相应的信息。

请注意，这个示例仅作为如何检测止损订单的触发，而不是一个完整的交易策略。可以根据实际交易策略调整限价订单和止损订单的设置。
